    public ICommand SubMenuCommand1 { get; private set; }
    public ICommand SubMenuCommand2 { get; private set; }

    public object ItemParameter { get; set; }
    public object SubItemParameter1 { get; set; }
    public object SubItemParameter2 { get; set; }

    public ItemViewModel()
    {
        MenuCommand = new RelayCommand(MenuCommandExecute);
        SubMenuCommand1 = new RelayCommand(SubMenuCommand1Execute);
        SubMenuCommand2 = new RelayCommand(SubMenuCommand2Execute);
    }

    private void MenuCommandExecute(object parameter)
    {
        // 处理菜单1的命令操作
    }

    private void SubMenuCommand1Execute(object parameter)
    {
        // 处理子菜单项1的命令操作
    }

    private void SubMenuCommand2Execute(object parameter)
    {
        // 处理子菜单项2的命令操作
    }

    // INotifyPropertyChanged的实现
}
```

3. 在ViewModel中使用常用的ICommand实现，例如RelayCommand：

```csharp
public class RelayCommand : ICommand
{
    private readonly Action<object> execute;
    private readonly Predicate<object> canExecute;

    public RelayCommand(Action<object> execute, Predicate<object> canExecute = null)
    {
        this.execute = execute;
        this.canExecute = canExecute;
    }

    public bool CanExecute(object parameter)
    {
        return canExecute == null || canExecute(parameter);
    }

    public void Execute(object parameter)
    {
        execute?.Invoke(parameter);
    }

    public event EventHandler CanExecuteChanged;

    public void RaiseCanExecuteChanged()
    {
        CanExecuteChanged?.Invoke(this, EventArgs.Empty);
    }
}
```

通过上述步骤，在点击ContextMenu中的菜单项时，会执行ViewModel中相应的命令操作。

在DataTemplate中为ListView添加多级菜单并添加点击事件，你可以按照以下步骤进行操作：

1. 在XAML中定义一个ContextMenu，并为它设置一个唯一的Key：

```xml
<ListView.ItemTemplate>
    <DataTemplate>
        <Grid>
            <!-- 定义数据模板的内容 -->
            <TextBlock Text="{Binding Name}" />

            <!-- 定义菜单 -->
            <TextBlock.ContextMenu>
                <ContextMenu x:Key="myContextMenu">
                    <MenuItem Header="菜单1" Click="Menu1_Click">
                        <!-- 添加子菜单项 -->
                        <MenuItem Header="子菜单项1" Click="SubMenu1_Click" />
                        <MenuItem Header="子菜单项2" Click="SubMenu2_Click" />
                    </MenuItem>
                </ContextMenu>
            </TextBlock.ContextMenu>
        </Grid>
    </DataTemplate>
</ListView.ItemTemplate>
```

