    MenuItem subMenuItem = (MenuItem)sender;
    string subMenuItemName = subMenuItem.Header.ToString(); // 获取菜单项名称

    // 执行子菜单项的操作，并根据名称进行区分
    if (subMenuItemName == "子菜单项1")
